INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('dietitian-moex-04524', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區老人的飲食營養建議，下列敘述何者正確？', '["由於老化，消化、吸收、代謝能力下降，老年人的熱量、蛋白質、大部分微量營養素的需求都 下降", "老年人的維生素D製造能力為年輕時的20％，又受限於行動以致日曬減少，故其維生素D建 議量是51歲以前的5倍，以預防骨質疏鬆症的危險上升", "老人若有不明原因體重減輕、營養不良、反覆跌倒、憂鬱、認知障礙、慢性疾病等問題，應接 受肌少症（sarcopenia）的診斷並關注生活行為", "有「肥胖型肌少症」（sarcopenicobesity）問題的老人，應控制飲食讓體重維持在標準範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04525', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關長期照護的未來主要發展趨勢，下列何者錯誤？', '["社區照護", "居家照護", "機構照護", "喘息照護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04526', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'NCDs已成為全球重大的健康威脅，其中「C」代表？', '["Care", "Certificates", "Community", "Communicable"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04527', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依老人福利機構設立標準規定長期照護型機構，有關工作人員的配置，下列何者錯誤？', '["隨時保持至少有一位護理人員值班", "每照顧一百人者，應置營養師一人", "日間每照顧五人，應置照顧服務員一人", "每照顧一百人者，應置社會工作人員一人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04528', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '為保障學校午餐品質，教育部訂定「學校午餐食物內容及營養基準」，關於此基準下列敘述何者正確？', '["依據「國人膳食營養素參考攝取量」及「每日飲食指南」訂定", "僅提供國小、國中午餐食物內容建議量，未提供高中食物內容建議量", "點心若為低糖綠豆薏仁湯、地瓜湯、紅豆湯等，則不限每週供應次數", "飲品、點心不可提供稀釋發酵乳，但可提供豆花、愛玉、布丁等食物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04529', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '林小姐於民國108年6月自營養系畢業，至民國114年5月仍未通過營養師考試，她決定繼續於 營養諮詢機構擔任營養顧問，在營養師指導下幫顧客進行營養評估與飲食指導。依據營養師法， 她和營養諮詢機構會受到的罰則為何？', '["本人及雇主各處新臺幣五萬元以上二十五萬元以下罰鍰", "只有本人處新臺幣五萬元以上二十五萬元以下罰鍰", "只有雇主處新臺幣五萬元以上二十五萬元以下罰鍰", "不會受罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04530', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一種飲品不得在國中以下學校校園內販售？', '["豆漿", "調味乳", "包裝飲用水", "百分之百果（蔬菜）汁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04531', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '一個飲食型態和大腸直腸癌關係的病例對照研究，下列飲食評估方法，何者最適當？', '["3天飲食紀錄，評估未來1個月的飲食", "飲食頻率問卷，詢問最近1個月的飲食", "飲食頻率問卷，詢問發病前5年的飲食", "24小時飲食回憶法，蒐集訪視前一天的飲食"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04532', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '常用的老年人營養狀況營養評估量表中，下列敘述何者正確？', '["MUST（MalnutritionUniversalScreeningTool）測量血清白蛋白濃度評估是否營養不良", "SGA（SubjectiveGlobalAssessment）評估不適用於早期偵測工具", "MNA（MiniNutritionalAssessment）以分數評估，包括一般評估、營養篩選與血液生化檢測三 部分", "INA（InstantNutritionalAssessment）主觀性評估，無分數或血液檢測評估，由經訓練之專業人 員執行營養診斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04533', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '為評估sarcopenia，可透過何種測量方法推算appendicularskeletalmusclemass？', '["Albumin", "Urinecreatinine", "Tricepsskinfoldthickness", "DualenergyX-rayabsorptiometry"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
